export const DOMAIN_ORDER = ['macro', 'fundamental', 'cross_asset', 'technical', 'sentiment', 'geopolitical'];

export const DOMAIN_LABELS: Record<string, string> = {
  macro:        'Macro & Monetary',
  fundamental:  'Corporate Fundamentals',
  cross_asset:  'Cross-Asset & Global',
  technical:    'Technical & Microstructure',
  sentiment:    'Sentiment & Behavioral',
  geopolitical: 'Geopolitical & Regulatory',
};

export function groupByDomain(params: Parameter[]): Map<string, Parameter[]> {
  const map = new Map<string, Parameter[]>();
  for (const d of DOMAIN_ORDER) map.set(d, []);
  for (const p of params) {
    if (!map.has(p.domain)) map.set(p.domain, []);
    map.get(p.domain)!.push(p);
  }
  return map;
}
